// Generates 6 dark-gym-colored test clips using FFmpeg's built-in color source.
// Skips any clip that already exists (e.g. real clips from Stage 2).
// These are solid-color 1080x1920 clips so normalization in Assemble Video is a no-op.
const { execSync } = require('child_process');
const fs = require('fs');

const data   = $input.first().json;
const jobId  = data.job_id;
const n8nIn  = '/data/ffmpeg/input';
const contIn = '/ffmpeg/input';

if (!fs.existsSync(n8nIn)) fs.mkdirSync(n8nIn, { recursive: true });

// Dark cinematic gym colors per scene
const colors = ['0x1a1a2e', '0x0f2a4a', '0x0a1628', '0x1c0a3a', '0x0a2a20', '0x1a1a2e'];
const labels = ['HOOK', 'SETUP', 'EXECUTION', 'ANATOMY', 'KEY TIP', 'CTA'];

const clipPaths = data.clip_paths || [];

for (let i = 0; i < 6; i++) {
  const n8nPath  = n8nIn  + '/' + jobId + '_scene' + (i+1) + '.mp4';
  const contPath = contIn + '/' + jobId + '_scene' + (i+1) + '.mp4';

  // Use existing file if already downloaded from Stage 2
  if (fs.existsSync(n8nPath)) {
    console.log('Scene ' + (i+1) + ' already exists — using real Seedance clip.');
    if (!clipPaths[i]) clipPaths[i] = n8nPath;
    continue;
  }

  console.log('Generating test clip ' + (i+1) + '/6 (' + labels[i] + ')...');
  const cmd =
    'docker exec qpc_ffmpeg_runner ffmpeg -y ' +
    '-f lavfi -i "color=c=' + colors[i] + ':s=1080x1920:r=24:d=5" ' +
    '-f lavfi -i "sine=frequency=0:sample_rate=44100:duration=5" ' +
    '-c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p ' +
    '-c:a aac -b:a 64k -shortest ' +
    '"' + contPath + '" && echo CLIP_OK';

  const res = execSync(cmd, { encoding: 'utf-8', timeout: 30000 });
  if (!res.includes('CLIP_OK')) throw new Error('Test clip ' + (i+1) + ' generation failed: ' + res.slice(-200));

  clipPaths[i] = n8nPath;
  console.log('  -> ' + n8nPath);
}

console.log('Test clips ready: ' + clipPaths.length + ' clips');
return [{ json: { ...data, clip_paths: clipPaths } }];

const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;
if (!body.job_id)     throw new Error('Stage 3 missing: job_id');
if (!body.clip_paths) throw new Error('Stage 3 missing: clip_paths');
if (!body.title)      throw new Error('Stage 3 missing: title');
return [{ json: {
  job_id:               body.job_id,
  exercise_name:        body.exercise_name || body.title,
  title:                body.title,
  hashtags:             body.hashtags || '#fitness #workout',
  narration:            body.narration || '',
  highlight_keywords:   body.highlight_keywords || [],
  muscle_labels_scene4: body.muscle_labels_scene4 || [],
  popup:                body.popup || {},
  clip_paths:           body.clip_paths,
  num_clips:            body.num_clips || body.clip_paths.length,
  clip_dur_sec:         body.clip_dur_sec || 5,
  audio_path:           body.audio_path || null,
  audio_duration:       body.audio_duration || 30,
  word_timings:         body.word_timings || [],
  ass_path:             body.ass_path || null,
  bgm_path:             body.bgm_path || null,
  sheet_row:            body.sheet_row || null,
  start_time:           body.start_time || Date.now()
}}];

const { execSync } = require('child_process');
const fs = require('fs');

const data   = $input.first().json;
const jobId  = data.job_id;
const clips  = data.clip_paths || [];
const N      = clips.length;
const popup  = data.popup || {};
const muscleLabels = data.muscle_labels_scene4 || [];

const n8nIn  = '/data/ffmpeg/input';
const n8nOut = '/data/ffmpeg/output';
const contIn = '/ffmpeg/input';
const contOut= '/ffmpeg/output';

if (!fs.existsSync(n8nOut)) fs.mkdirSync(n8nOut, { recursive: true });

function run(cmd, ms) {
  ms = ms || 120000;
  console.log('CMD: ' + cmd.slice(0, 220));
  let out = '';
  try { out = execSync(cmd, { encoding: 'utf-8', timeout: ms }); }
  catch(e) { out = (e.stdout||'') + (e.stderr||''); }
  return out.toString();
}

// ─── STEP 1: Create iOS-style notification PNG via ImageMagick (once per instance) ─
const overlayDir  = '/ffmpeg/config/overlay';
const notifBase   = overlayDir + '/ios_notification_bg.png';
const notifExists = run('docker exec qpc_ffmpeg_runner test -f "' + notifBase + '" && echo OK').includes('OK');

if (!notifExists) {
  run('docker exec qpc_ffmpeg_runner mkdir -p "' + overlayDir + '"');

  // Try ImageMagick first (rounded corners)
  const imCmd =
    'docker exec qpc_ffmpeg_runner convert ' +
    '-size 550x115 xc:none ' +
    '-fill "#EBEBEB" -draw "roundrectangle 0,0 549,114 13,13" ' +
    '-fill "#C7C7CC" -draw "rectangle 0,0 549,2" ' +
    '-fill "#34C759" -draw "circle 26,28 40,28" ' +
    '"' + notifBase + '" && echo IM_OK';
  const imRes = run(imCmd, 20000);

  if (!imRes.includes('IM_OK')) {
    // Fallback: Python PIL
    const py = n8nIn + '/_mknotif.py';
    fs.writeFileSync(py,
      'try:\n' +
      '    from PIL import Image, ImageDraw\n' +
      '    img = Image.new("RGBA",(550,115),(0,0,0,0))\n' +
      '    d = ImageDraw.Draw(img)\n' +
      '    d.rounded_rectangle([0,0,549,114],radius=13,fill=(235,235,235,245))\n' +
      '    d.rectangle([0,0,549,2],fill=(199,199,204,255))\n' +
      '    d.ellipse([12,14,40,42],fill=(52,199,89,255))\n' +
      '    import os; os.makedirs("/ffmpeg/config/overlay",exist_ok=True)\n' +
      '    img.save("/ffmpeg/config/overlay/ios_notification_bg.png","PNG")\n' +
      '    print("PNG_OK")\n' +
      'except Exception as e:\n' +
      '    print("PNG_FAIL:",e)\n'
    );
    const pyRes = run('docker exec qpc_ffmpeg_runner python3 "/ffmpeg/input/_mknotif.py"', 20000);
    if (!pyRes.includes('PNG_OK')) console.warn('Notification PNG failed — will use drawbox fallback');
  }
}

const hasNotif = run('docker exec qpc_ffmpeg_runner test -f "' + notifBase + '" && echo OK').includes('OK');
console.log('Notification PNG: ' + (hasNotif ? 'READY (rounded corners)' : 'using drawbox fallback'));

// ─── STEP 2: Normalize all clips to 1080x1920 ───────────────────────────────
for (let i = 0; i < N; i++) {
  const inFile  = clips[i].replace('/data/ffmpeg', '/ffmpeg');
  const outFile = contIn + '/' + jobId + '_norm' + i + '.mp4';
  run(
    'docker exec qpc_ffmpeg_runner ffmpeg -y -i "' + inFile + '" ' +
    '-vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black" ' +
    '-r 24 -c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p -an "' + outFile + '"',
    120000
  );
}

// ─── STEP 3: XFADE transitions (variety cycle) ──────────────────────────────
const transitions = ['fade', 'wipeleft', 'slidedown', 'circlecrop', 'wiperight', 'slideleft'];
const CLIP_DUR = 5.0;
const FADE_DUR = 0.4;
let withTransitions;

if (N === 1) {
  withTransitions = contIn + '/' + jobId + '_norm0.mp4';
} else {
  const inputs = Array.from({length:N}, (_,i) => '-i "' + contIn + '/' + jobId + '_norm' + i + '.mp4"').join(' ');
  let xf = '';
  let prev = '[0:v]';
  for (let i = 1; i < N; i++) {
    const t   = transitions[(i-1) % transitions.length];
    const off = (i * (CLIP_DUR - FADE_DUR)).toFixed(1);
    const o   = (i === N-1) ? '[vout]' : '[x'+i+']';
    xf += prev + '['+i+':v]xfade=transition='+t+':duration='+FADE_DUR+':offset='+off+o+';';
    prev = o;
  }
  run(
    'docker exec qpc_ffmpeg_runner ffmpeg -y ' + inputs +
    ' -filter_complex "' + xf.slice(0,-1) + '" -map "[vout]" -c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p "' +
    contIn + '/' + jobId + '_xfade.mp4"',
    300000
  );
  withTransitions = contIn + '/' + jobId + '_xfade.mp4';
}

// ─── STEP 4: Check assets ───────────────────────────────────────────────────
// No logo overlay for fitness channel — text-only branding
const hasLogo = false;

let narFile = data.audio_path || null;
if (narFile) {
  const c = narFile.replace('/data/ffmpeg','/ffmpeg');
  narFile  = run('docker exec qpc_ffmpeg_runner test -f "' + c + '" && echo OK').includes('OK') ? c : null;
}

let bgmFile = data.bgm_path ? data.bgm_path.replace('/data/ffmpeg','/ffmpeg') : null;
const hasBgm = !!(bgmFile && run('docker exec qpc_ffmpeg_runner test -f "' + bgmFile + '" && echo OK').includes('OK'));

const assFile = data.ass_path ? data.ass_path.replace('/data/ffmpeg','/ffmpeg') : null;
const hasAss  = !!(assFile && run('docker exec qpc_ffmpeg_runner test -f "' + assFile + '" && echo OK').includes('OK'));

console.log('Assets | logo:'+hasLogo+' | voice:'+!!narFile+' | bgm:'+hasBgm+' | ass:'+hasAss);

// ─── STEP 5: Build FFmpeg input list ────────────────────────────────────────
const inp   = ['-i "' + withTransitions + '"'];
const notifI = hasNotif ? inp.push('-i "' + notifBase + '"') - 1 : -1;
const narI   = narFile   ? inp.push('-i "' + narFile   + '"') - 1 : -1;
const bgmI   = hasBgm    ? inp.push('-i "' + bgmFile   + '"') - 1 : -1;

// ─── STEP 6: Video filter chain ─────────────────────────────────────────────
let lbl = 0;
let vf  = '';
let cur = '0:v';

// No channel branding overlay — clean video output

// ─── POPUP NOTIFICATION ─────────────────────────────────────────────────────
const popupStart = popup.start_sec || 5;
const popupEnd   = popup.end_sec   || 9;

function ffText(s) {
  return (s||'').replace(/['":(),\[\]]/g,'').replace(/[^\x20-\x7E]/g,'').slice(0,45);
}
const pApp = ffText(popup.app_name || 'FitChannel');
const pMsg = ffText(popup.message  || 'Get the full program');
const en   = "between(t," + popupStart + "," + popupEnd + ")";

if (hasNotif) {
  // PNG overlay — proper rounded corners, real iOS look
  vf += ';['+notifI+':v]scale=550:115,format=rgba,colorchannelmixer=aa=0.96[notif];['+cur+'][notif]overlay=x=25:y=45:format=auto:enable=\''+en+'\'[vb'+lbl+']';
  cur='vb'+lbl; lbl++;
  // App name (double-draw bold effect)
  vf += ';['+cur+"]drawtext=text='"+pApp+"':fontcolor=0x111111:fontsize=28:x=53:y=87:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='"+pApp+"':fontcolor=0x111111:fontsize=28:x=52:y=87:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
  // Message text
  vf += ';['+cur+"]drawtext=text='"+pMsg+"':fontcolor=0x555555:fontsize=23:x=52:y=120:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
} else {
  // drawbox fallback
  vf += ';['+cur+']drawbox=x=25:y=45:w=545:h=112:color=0xEBEBEB@0.96:t=fill:enable=\''+en+'\'[vb'+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+']drawbox=x=25:y=45:w=545:h=3:color=0xC7C7CC@1:t=fill:enable=\''+en+'\'[vb'+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+']drawbox=x=26:y=46:w=26:h=26:color=0x34C759@1:t=fill:enable=\''+en+'\'[vb'+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='MESSAGES':fontcolor=0x888888:fontsize=20:x=60:y=56:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='now':fontcolor=0xAAAAAA:fontsize=19:x=498:y=56:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='"+pApp+"':fontcolor=0x111111:fontsize=27:x=60:y=87:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
  vf += ';['+cur+"]drawtext=text='"+pMsg+"':fontcolor=0x444444:fontsize=23:x=60:y=120:enable='"+en+"'[vb"+lbl+']'; cur='vb'+lbl; lbl++;
}

// ─── MUSCLE LABELS (Scene 4 = t:15-20s) ──────────────────────────────────────
const labelEn = "between(t,15,20)";
if (muscleLabels && muscleLabels.length > 0) {
  for (const ml of muscleLabels) {
    if (!ml.name) continue;
    const name = ml.name.replace(/['":(),\[\]]/g,'').slice(0,24);
    const lx   = Math.max(20, Math.min(840, Math.round((ml.x_pct||0.5) * 1080) - 130));
    const ly   = Math.max(20, Math.min(1860, Math.round((ml.y_pct||0.5) * 1920) - 20));
    vf += ';['+cur+"]drawtext=text='"+name+"':fontcolor=white:fontsize=36:x="+lx+":y="+ly+":bordercolor=black:borderw=4:enable='"+labelEn+"'[vb"+lbl+']';
    cur='vb'+lbl; lbl++;
  }
  console.log('Muscle labels: ' + muscleLabels.length + ' labels on Scene 4 (t=15-20s)');
}

// ─── ASS Subtitles ───────────────────────────────────────────────────────────
if (hasAss) {
  vf += ";["+cur+"]subtitles=filename='"+assFile+"'[outv]";
} else {
  vf += ";["+cur+"]copy[outv]";
}

// ─── Audio mix ────────────────────────────────────────────────────────────────
let afilters = '';
let amap     = '-an';
if (narFile && hasBgm) {
  afilters = ';['+narI+':a]volume=1.0[nar];['+bgmI+':a]volume=0.22[bgm];[nar][bgm]amix=inputs=2:duration=first:dropout_transition=2[aout]';
  amap = '-map "[aout]"';
} else if (narFile) {
  afilters = ';['+narI+':a]aformat=sample_fmts=fltp[aout]';
  amap = '-map "[aout]"';
} else if (hasBgm) {
  afilters = ';['+bgmI+':a]volume=0.85[aout]';
  amap = '-map "[aout]"';
}

const fullFilter = (vf + afilters).replace(/^;/, "");
const dur        = data.audio_duration ? Math.ceil(data.audio_duration) + 2 : 32;
const hasAudio   = amap !== '-an';

console.log('Filter nodes: '+lbl+' | audio:'+hasAudio+' | subtitles:'+hasAss+' | popup_png:'+hasNotif);

// ─── Final render ─────────────────────────────────────────────────────────────
const cmd =
  'docker exec qpc_ffmpeg_runner ffmpeg -y ' + inp.join(' ') +
  ' -filter_complex "' + fullFilter + '" -map "[outv]" ' + amap +
  ' -c:v libx264 -crf 18 -preset fast -pix_fmt yuv420p -movflags +faststart' +
  (hasAudio ? ' -c:a aac -b:a 192k' : '') +
  ' -t ' + dur + ' "' + contOut + '/' + jobId + '_final.mp4" && echo FINAL_OK';

const result = run(cmd, 900000);
if (!result.includes('FINAL_OK')) throw new Error('Final render failed:\n' + result.slice(-800));

const finalPath = n8nOut + '/' + jobId + '_final.mp4';
if (!fs.existsSync(finalPath)) throw new Error('Output not on disk: ' + finalPath);

const elapsed = Math.round((Date.now() - data.start_time) / 1000);
console.log('Assembly complete | ' + jobId + ' | ' + elapsed + 's | ' + finalPath);

return [{ json: { ...data, final_video_path: finalPath, output_filename: jobId + '_final.mp4', assembly_time_sec: elapsed } }];

const fs           = require('fs');
const { execSync } = require('child_process');

const data     = $input.first().json;
const filePath = data.final_video_path;
const contPath = filePath.replace('/data/ffmpeg', '/ffmpeg');

if (!fs.existsSync(filePath)) throw new Error('Final video missing: ' + filePath);

const folderId = $env.GOOGLE_DRIVE_FOLDER_ID || '';
const token    = $env.GOOGLE_DRIVE_ACCESS_TOKEN || '';

if (!token || !folderId) {
  console.warn('GOOGLE_DRIVE_ACCESS_TOKEN or GOOGLE_DRIVE_FOLDER_ID not set — skipping Drive upload.');
  console.log('Video ready at: ' + filePath);
  return [{ json: { ...data, drive_file_id: null, drive_video_url: null, drive_skipped: true } }];
}

const metadata    = JSON.stringify({ name: data.output_filename, parents: [folderId] });
const escapedMeta = metadata.replace(/"/g, '\\"');

const res = execSync(
  'docker exec qpc_ffmpeg_runner curl -s -X POST ' +
  '-H "Authorization: Bearer ' + token + '" ' +
  '-F "metadata=' + escapedMeta + ';type=application/json" ' +
  '-F "file=@' + contPath + ';type=video/mp4" ' +
  '"https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id"',
  { encoding: 'utf-8', timeout: 600000 }
);

let parsed = {};
try { parsed = JSON.parse(res); } catch(e) {}

const fileId   = parsed.id || null;
const driveUrl = fileId ? 'https://drive.usercontent.google.com/download?id=' + fileId + '&export=download' : null;
console.log('Drive: ' + (fileId ? 'OK -> ' + fileId : 'failed: ' + res.slice(0,200)));

return [{ json: { ...data, drive_file_id: fileId, drive_video_url: driveUrl } }];

